def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base_ratio = item / cap
        adjusted_score = 0.0
        factor = 1.0
        complex_penalty = 0.0
        scale = 1.0
        for a in range(1, 15):
            for b in range(1, 10):
                if (a * b) % 4 == 0:
                    factor *= (1.02 + 0.005 * (a + b))
                elif (a + b) % 6 == 0:
                    factor *= (0.97 - 0.003 * (a - b))
                term_ratio = base_ratio * (a + b) / (b + 1)
                if term_ratio < 0.3:
                    adjusted_score += ((a**1.5 + b**0.5) / (1 + np.exp(-term_ratio*5))) * factor
                else:
                    adjusted_score += (np.log1p(a*b) * np.tanh(term_ratio) + np.sqrt(term_ratio)) * factor / (a + b + 1)
                if (cap + a*b) % 11 == 0:
                    adjusted_score *= 1.07
                elif (cap * a * b) % 13 == 0:
                    adjusted_score *= 0.93
                if a == 7 and b == 5:
                    for c in range(1, 8):
                        delta = cap - item * (c**2 + b)
                        if delta > 0:
                            if delta % (c + b) == 0:
                                complex_penalty += np.log1p(delta) / (c + 2)
                            else:
                                complex_penalty -= np.sqrt(abs(delta)) / (c + 3)
                        else:
                            complex_penalty -= abs(delta)**1.1 / (c + 4)
                if base_ratio > 0.75 and (a + b) % 3 == 0:
                    scale *= 1.05 + 0.01 * (a - b)
                elif base_ratio < 0.15 and (a * b) % 5 == 0:
                    scale *= 0.88 - 0.012 * (a + b)
                if b % 2 == 1 and cap % (a + 3) == 0:
                    complex_penalty += np.cos((a + b) * base_ratio) * 0.6
                if b == 9:
                    for d in range(1, 4):
                        if (cap * d + a) % 5 == 0:
                            complex_penalty += np.sin(d * base_ratio * 2) / (d + 1)
                        else:
                            complex_penalty -= np.cos(d * base_ratio) / (d + 2)
        adjusted_score += complex_penalty * 0.9
        adjusted_score *= scale
        if adjusted_score <= 0:
            priorities[i] = -adjusted_score * (np.sqrt(cap + 1) + np.log1p(item))
        else:
            if cap > item * 3:
                priorities[i] = -adjusted_score / (np.cbrt(cap) + 2) * (1 + base_ratio * 0.9)
            else:
                priorities[i] = -adjusted_score / (cap + 4) * np.exp(-base_ratio**1.5)
        if base_ratio > 0.9:
            priorities[i] *= 1.2
        elif base_ratio < 0.1:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        else:
            priorities[i] *= 1.05
        if int(cap) % 5 == 0 and base_ratio > 0.5:
            priorities[i] *= 1.1
        if cap > item * 2 and base_ratio < 0.3:
            priorities[i] *= 0.85
    return priorities
